import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE = 'http://localhost:5001/api';

function App() {
  const [activeTab, setActiveTab] = useState('checklist');

  return (
    <div className="app-container">
      <div className="header">
        <h1>📄 IPQC OCR System</h1>
        <p>Extract data from IPQC checklists and fill Excel automatically</p>
      </div>

      <div className="tab-bar">
        <button
          className={`tab-btn ${activeTab === 'checklist' ? 'active' : ''}`}
          onClick={() => setActiveTab('checklist')}
        >
          📋 IPQC Checklist
        </button>
        <button
          className={`tab-btn ${activeTab === 'ocr' ? 'active' : ''}`}
          onClick={() => setActiveTab('ocr')}
        >
          🔗 Manual OCR
        </button>
      </div>

      {activeTab === 'checklist' ? <ChecklistTab /> : <OcrTab />}

      <div className="footer">
        <p>IPQC OCR System v2.0 | Powered by Azure Document Intelligence</p>
      </div>
    </div>
  );
}

// ========== IPQC CHECKLIST TAB ==========
function ChecklistTab() {
  const [loading, setLoading] = useState(false);
  const [checklists, setChecklists] = useState([]);
  const [error, setError] = useState('');
  const [processing, setProcessing] = useState(null); // index being processed
  const [processResults, setProcessResults] = useState({}); // { index: result }
  const [expandedRow, setExpandedRow] = useState(null);

  // Filters (optional - for narrowing down)
  const [filterDate, setFilterDate] = useState('');
  const [filterShift, setFilterShift] = useState('');
  const [filterLine, setFilterLine] = useState('');

  // Auto-fetch ALL checklists on mount
  const fetchAll = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`${API_BASE}/ipqc-checklist/fetch`, {});
      if (response.data.success) {
        setChecklists(response.data.data || []);
        if ((response.data.data || []).length === 0) {
          setError('No IPQC checklists found.');
        }
      } else {
        setError(response.data.error || 'Failed to fetch checklists');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'Failed to fetch checklists');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  // Filter checklists locally (no re-fetch needed)
  const filtered = checklists.filter(item => {
    if (filterDate && item.date !== filterDate) return false;
    if (filterShift && item.Shift !== filterShift) return false;
    if (filterLine && item.Line !== filterLine) return false;
    return true;
  });

  // Get unique values for filter dropdowns
  const uniqueDates = [...new Set(checklists.map(c => c.date).filter(Boolean))].sort().reverse();
  const uniqueShifts = [...new Set(checklists.map(c => c.Shift).filter(Boolean))];
  const uniqueLines = [...new Set(checklists.map(c => c.Line).filter(Boolean))].sort();

  // Process a single checklist through Azure OCR
  const handleProcess = async (checklist, index) => {
    setProcessing(index);
    setError('');

    try {
      const response = await axios.post(`${API_BASE}/ipqc-checklist/process-item`, { checklist });
      if (response.data.success) {
        setProcessResults(prev => ({ ...prev, [index]: response.data }));
        setExpandedRow(index);
      } else {
        setError(response.data.error || 'Processing failed');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'OCR processing failed');
    } finally {
      setProcessing(null);
    }
  };

  const handleDownload = (filename) => {
    window.open(`${API_BASE}/ipqc-ocr/download/${filename}`, '_blank');
  };

  return (
    <div className="main-card">
      <div className="section-header-row">
        <div>
          <h2 className="section-title">📋 All IPQC Checklists</h2>
          <p className="section-desc">All available checklists loaded automatically. Filter & process directly with Azure OCR.</p>
        </div>
        <button onClick={fetchAll} disabled={loading} className="refresh-btn">
          {loading ? <><span className="spinner small"></span></> : <>🔄</>} Refresh
        </button>
      </div>

      {/* Inline Filters */}
      <div className="filter-row compact">
        <div className="filter-item">
          <label>Date</label>
          <select value={filterDate} onChange={(e) => setFilterDate(e.target.value)}>
            <option value="">All Dates ({uniqueDates.length})</option>
            {uniqueDates.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
        <div className="filter-item">
          <label>Shift</label>
          <select value={filterShift} onChange={(e) => setFilterShift(e.target.value)}>
            <option value="">All Shifts</option>
            {uniqueShifts.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="filter-item">
          <label>Line</label>
          <select value={filterLine} onChange={(e) => setFilterLine(e.target.value)}>
            <option value="">All Lines</option>
            {uniqueLines.map(l => <option key={l} value={l}>{l}</option>)}
          </select>
        </div>
        <div className="filter-item">
          <span className="filter-count">{filtered.length} of {checklists.length} shown</span>
        </div>
      </div>

      {error && <div className="error-message">❌ {error}</div>}

      {loading && checklists.length === 0 && (
        <div className="status-message"><span className="spinner small"></span> Loading all IPQC checklists...</div>
      )}

      {/* Checklist Table */}
      {filtered.length > 0 && (
        <div className="checklist-results">
          <div className="checklist-table-wrapper">
            <table className="checklist-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Date</th>
                  <th>Line</th>
                  <th>Shift</th>
                  <th>Pages</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((item, idx) => {
                  const globalIdx = checklists.indexOf(item);
                  const result = processResults[globalIdx];
                  const isProcessing = processing === globalIdx;
                  const isExpanded = expandedRow === globalIdx;

                  return (
                    <React.Fragment key={globalIdx}>
                      <tr className={result ? 'row-processed' : ''} onClick={() => result && setExpandedRow(isExpanded ? null : globalIdx)} style={{ cursor: result ? 'pointer' : 'default' }}>
                        <td>{idx + 1}</td>
                        <td><strong>{item.date || '—'}</strong></td>
                        <td>{item.Line || '—'}</td>
                        <td><span className={`shift-badge ${(item.Shift || '').toLowerCase()}`}>{item.Shift || '—'}</span></td>
                        <td><span className="page-badge">{item.totalPages || 0}</span></td>
                        <td>
                          {isProcessing ? (
                            <span className="status-tag processing"><span className="spinner small"></span> OCR Running...</span>
                          ) : result ? (
                            <span className="status-tag done">✅ Processed</span>
                          ) : (
                            <span className="status-tag pending">⏳ Pending</span>
                          )}
                        </td>
                        <td>
                          {isProcessing ? (
                            <span className="processing-label">Please wait...</span>
                          ) : result ? (
                            <div className="action-btns">
                              {result.excelGenerated && (
                                <button className="download-btn small" onClick={(e) => { e.stopPropagation(); handleDownload(result.outputFile); }}>
                                  📥 Excel
                                </button>
                              )}
                              <button className="view-btn small" onClick={(e) => { e.stopPropagation(); setExpandedRow(isExpanded ? null : globalIdx); }}>
                                {isExpanded ? '▲ Hide' : '▼ View'}
                              </button>
                            </div>
                          ) : (
                            <button className="process-btn small" onClick={() => handleProcess(item, globalIdx)} disabled={processing !== null || item.totalPages === 0}>
                              🚀 Process OCR
                            </button>
                          )}
                        </td>
                      </tr>

                      {/* Expanded row - show OCR results */}
                      {isExpanded && result && (
                        <tr className="expanded-row">
                          <td colSpan="7">
                            <div className="expanded-content">
                              <div className="result-summary">
                                <div className="result-item"><span className="label">Pages Processed</span><span className="value">{result.pagesProcessed}</span></div>
                                <div className="result-item"><span className="label">Excel Ready</span><span className="value">{result.excelGenerated ? '✅ Yes' : '❌ No'}</span></div>
                              </div>

                              {result.extractedData && result.extractedData.length > 0 && (
                                <div className="extracted-pages">
                                  {result.extractedData.map((page, pi) => (
                                    <div key={pi} className="page-data">
                                      <h5>Page {page.pageNumber || pi + 1}</h5>
                                      {page.error ? (
                                        <p className="page-error">Error: {page.error}</p>
                                      ) : (
                                        <div className="page-details">
                                          {page.serialNumbers?.length > 0 && (
                                            <div className="detail-row">
                                              <span className="detail-label">Serials ({page.serialNumbers.length}):</span>
                                              <div className="serial-grid">
                                                {page.serialNumbers.slice(0, 8).map((s, si) => (
                                                  <span key={si} className="serial-item">{s}</span>
                                                ))}
                                                {page.serialNumbers.length > 8 && <span className="serial-item more">+{page.serialNumbers.length - 8}</span>}
                                              </div>
                                            </div>
                                          )}
                                          {page.temperatures?.length > 0 && (
                                            <div className="detail-row"><span className="detail-label">Temps:</span><span>{page.temperatures.join(', ')}</span></div>
                                          )}
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                </div>
                              )}

                              {result.excelGenerated && (
                                <button className="download-btn large" onClick={() => handleDownload(result.outputFile)}>
                                  📥 Download Filled Excel
                                </button>
                              )}
                            </div>
                          </td>
                        </tr>
                      )}
                    </React.Fragment>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

// ========== MANUAL OCR TAB ==========
function OcrTab() {
  const [pdfUrls, setPdfUrls] = useState('');
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState('');
  const [error, setError] = useState('');
  const [result, setResult] = useState(null);
  const [extractedData, setExtractedData] = useState(null);

  const handleProcessOCR = async () => {
    if (!pdfUrls.trim()) { setError('Please enter PDF URLs (one per line)'); return; }
    setLoading(true);
    setStatus('Processing PDF files with Azure Document Intelligence...');
    setError('');
    setResult(null);
    setExtractedData(null);

    try {
      const urls = pdfUrls.split('\n').map(url => url.trim()).filter(url => url);
      setStatus(`Processing ${urls.length} PDF file(s)...`);
      const response = await axios.post(`${API_BASE}/ipqc-ocr/process-from-urls`, { pdfUrls: urls });
      if (response.data.success) {
        setResult(response.data);
        setExtractedData(response.data.extractedData);
        setStatus('✅ OCR Complete! Excel file ready for download.');
      } else {
        setError(response.data.error || 'OCR processing failed');
        setStatus('');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'Failed to process OCR');
      setStatus('');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadExcel = () => {
    if (result && result.outputFile) {
      const filename = result.outputFile.includes('\\') || result.outputFile.includes('/')
        ? result.outputFile.split(/[\\\/]/).pop() : result.outputFile;
      window.open(`${API_BASE}/ipqc-ocr/download/${filename}`, '_blank');
    }
  };

  return (
    <div className="main-card">
      <h2 className="section-title">🔗 Manual OCR Processing</h2>
      <p className="section-desc">Paste PDF URLs to process through Azure OCR and generate Excel.</p>

      <div className="input-section">
        <label htmlFor="pdfUrls"><span className="label-icon">🔗</span> Enter PDF URLs (one per line):</label>
        <textarea
          id="pdfUrls"
          value={pdfUrls}
          onChange={(e) => setPdfUrls(e.target.value)}
          placeholder={`https://example.com/page1.pdf\nhttps://example.com/page2.pdf`}
          rows={6}
          disabled={loading}
        />
      </div>

      <div className="button-section">
        <button onClick={handleProcessOCR} disabled={loading || !pdfUrls.trim()} className="process-btn">
          {loading ? <><span className="spinner"></span> Processing...</> : <>🚀 Process OCR</>}
        </button>
        {result && (
          <button onClick={handleDownloadExcel} className="download-btn">📥 Download Excel</button>
        )}
      </div>

      {status && <div className="status-message">{status}</div>}
      {error && <div className="error-message">❌ {error}</div>}

      {extractedData && (
        <div className="extracted-data">
          <h3>📋 Extracted Data Preview</h3>
          <div className="data-grid">
            {extractedData.date && <div className="data-item"><span className="label">Date:</span><span className="value">{extractedData.date}</span></div>}
            {extractedData.lotNumber && <div className="data-item"><span className="label">Lot Number:</span><span className="value">{extractedData.lotNumber}</span></div>}
            {extractedData.type && <div className="data-item"><span className="label">Type:</span><span className="value">{extractedData.type}</span></div>}
            {extractedData.cell && <div className="data-item"><span className="label">Cell:</span><span className="value">{extractedData.cell}</span></div>}
          </div>
          {extractedData.serialNumbers && extractedData.serialNumbers.length > 0 && (
            <div className="serial-section">
              <h4>Serial Numbers ({extractedData.serialNumbers.length})</h4>
              <div className="serial-grid">
                {extractedData.serialNumbers.slice(0, 20).map((serial, idx) => (
                  <span key={idx} className="serial-item">{serial}</span>
                ))}
                {extractedData.serialNumbers.length > 20 && (
                  <span className="serial-item more">+{extractedData.serialNumbers.length - 20} more</span>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default App;
